import ExecutionEnvironment from 'exenv';
import includes from './includes';

const ANDROID_OS = 'android';
const IOS_OS = 'ios';
const LINUX_OS = 'linux';
const MAC_OS = 'mac os';
const WINDOWS_OS = 'windows';

const macosPlatforms = ['Macintosh', 'MacIntel', 'MacPPC', 'Mac68K'];
const iosPlatforms = ['iPhone', 'iPad', 'iPod'];
const windowsPlatforms = ['Win32', 'Win64', 'Windows', 'WinCE'];

const getOsName = () => {
  if (!ExecutionEnvironment.canUseDOM) return;

  const userAgent = window?.navigator?.userAgent;
  // window.navigator.userAgentData is not supported on Firefox so we use window.navigator.platform instead
  const platform = window?.navigator?.platform;

  if (includes(macosPlatforms, platform)) return MAC_OS;
  if (includes(iosPlatforms, platform)) return IOS_OS;
  if (includes(windowsPlatforms, platform)) return WINDOWS_OS;
  if (/Android/.test(userAgent)) return ANDROID_OS;
  if (/Linux/.test(userAgent)) return LINUX_OS;

  return undefined;
};

export default getOsName;
